import logging
import os

class FilePathContext:
    def __init__(self, path):
        self.filepath = path if isinstance(path, str) else path.filepath
    def open(self, mode):
        return open(self.filepath, mode)

def resolve_format(fmt, filepath):
    # Simple detection by extension
    _, ext = os.path.splitext(filepath.lower())
    if ext in ['.tsv', '.txt']:
        return 'tsv'
    if ext in ['.yaml', '.yml']:
        return 'yaml'
    return None

def parse_exchange_table_file_dynamic(f):
    # Read header and determine column mapping
    header_line = f.readline()
    if not header_line:
        return
    headers = header_line.strip().split('\t')
    # Find indices for required columns
    try:
        idx_compound = headers.index('compound')
        idx_lower = headers.index('lower')
        idx_upper = headers.index('upper')
    except ValueError:
        # If required columns not found, raise error or treat as no header?
        # According to spec, we assume they exist; if not, raise ParseError
        raise ParseError('TSV header missing required columns: compound, lower, upper')
    for line in f:
        parts = line.strip().split('\t')
        if len(parts) <= max(idx_compound, idx_lower, idx_upper):
            continue
        yield {
            'compound': parts[idx_compound],
            'lower': float(parts[idx_lower]),
            'upper': float(parts[idx_upper])
        }

def parse_exchange_yaml_file(context, f, default_compartment):
    # Minimal YAML-like stub: each line "compound:lower:upper[:compartment]"
    for line in f:
        parts = line.strip().split(':')
        if len(parts) < 3:
            continue
        entry = {
            'compound': parts[0],
            'lower': float(parts[1]),
            'upper': float(parts[2]),
            'compartment': parts[3] if len(parts) > 3 else default_compartment
        }
        yield entry

class ParseError(Exception):
    pass

logger = logging.getLogger(__name__)

def parse_exchange_file(path, default_compartment):
    """Parse a file as a list of exchange compounds with flux limits.

    The file format is detected and the file is parsed accordingly. Path can
    be given as a string or a context.
    """
    context = FilePathContext(path)
    format = resolve_format(None, context.filepath)
    # If extension-based detection fails, try content sniffing
    if format is None:
        # Read first line to guess format
        with context.open('r') as f:
            first_line = f.readline()
        if not first_line:
            raise ParseError('Empty file: {}'.format(context.filepath))
        first_line_stripped = first_line.strip()
        # Heuristic: if line contains a colon, treat as YAML; if contains a tab, treat as TSV
        if ':' in first_line_stripped:
            format = 'yaml'
        elif '\t' in first_line_stripped:
            format = 'tsv'
        else:
            raise ParseError('Unable to detect format of exchange file {}'.format(context.filepath))

    if format == 'tsv':
        logger.debug('Parsing exchange file {} as TSV'.format(context.filepath))
        with context.open('r') as f:
            for entry in parse_exchange_table_file_dynamic(f):
                yield entry
    elif format == 'yaml':
        logger.debug('Parsing exchange file {} as YAML'.format(context.filepath))
        with context.open('r') as f:
            for entry in parse_exchange_yaml_file(context, f, default_compartment):
                yield entry
    else:
        raise ParseError('Unexpected format: {}'.format(format))

def main():
    # Create a sample TSV exchange file
    tsv_path = 'exchange_limits.tsv'
    with open(tsv_path, 'w') as f:
        f.write('compound\tlower\tupper\n')
        f.write('Glucose\t-10\t100\n')
        f.write('Lactate\t0\t50\n')

    print('Parsing TSV file:')
    for entry in parse_exchange_file(tsv_path, default_compartment='c'):
        print(entry)

    # Create a sample YAML-like exchange file
    yaml_path = 'exchange_limits.yaml'
    with open(yaml_path, 'w') as f:
        f.write('Glucose:-10:100:cytosol\n')
        f.write('O2:-1000:1000:mitochondria\n')

    print('\nParsing YAML file:')
    for entry in parse_exchange_file(yaml_path, default_compartment='c'):
        print(entry)

if __name__ == '__main__':
    main()
